		expertise_th = '"ปรมาจารย์ผู้สง่างามแห่งโปเกมอนบิน" ฟอล์คเนอร์มีชื่อเสียงจากภาพลักษณ์ที่เท่และหล่อเหลา แต่เมื่อเทียบกับพ่อของเขาแล้วกลับดูไม่เข้ากันเลย บางทีอาจเป็นเพราะเหตุนี้ ฟอล์คเนอร์จึงมุ่งมั่นที่จะเป็นปรมาจารย์แห่งโปเกมอนบินที่ยิ่งใหญ่ที่สุด',
		desc = '“志向高远，就能飞到任何地方。”\n“华丽翱翔在天空中的鸟宝可梦真正的力量，我会让你领教的！…爸爸！在天上看着我的战斗吧！”\n“……”\n“我没叫你……”',
		desc_tw = '“志向高遠，就能飛到任何地方。”\n“華麗翱翔在天空中的鳥寶可夢真正的力量，我會讓你領教的！…爸爸！在天上看著我的戰鬥吧！”\n“……”\n“我沒叫你……”',
		desc_en = 'If you have high ambitions, you can fly anywhere."\n"The true power of the gorgeous bird Pokémon soaring in the sky, I will let you understand it! …dad! Watch my battle in the sky!"\n“……”\n"I didn\'t call you...',
		desc_vn = 'Nếu bạn có tham vọng cao, bạn có thể bay đến bất cứ đâu.\n"Sức mạnh thực sự của Pokémon chim lộng lẫy bay lượn trên bầu trời, tôi sẽ cho bạn hiểu điều đó! …cha! Hãy xem trận chiến của con trên bầu trời!"\n“……”\n"Con không gọi cha..."',
		desc_kr = '꿈이 크면 어디든 날아갈 수 있다."\n"하늘에서 화려하게 날아다니는 포켓몬의 진정한 힘, 내가 가르쳐줄게!… 아빠! 하늘에서 나의 전투를 지켜보세요!”\n“……”\n“널 안 불렀는데…',
		desc_pt = 'Se você tem grandes ambições, pode voar para qualquer lugar."\n"O verdadeiro poder do lindo Pokémon pássaro voando alto no céu, eu vou deixar você entender! …pai! Assista minha batalha no céu!"\n"……”\n"Eu não chamei você...',
		desc_th = '“หากคุณมีความทะเยอทะยานสูง คุณสามารถบินได้ทุกที่”\n“พลังที่แท้จริงของโปเกมอนนกที่สวยงามที่โบยบินอยู่บนท้องฟ้า ฉันจะให้คุณเข้าใจมัน! …พ่อ! ดูการต่อสู้ของฉันบนท้องฟ้าสิ!”\n“……”\n“ฉันไม่ได้เรียกคุณว่า...”'
	},
