		expertise_th = 'หลานชายของหมอโอ๊ค เขาเป็นคนมั่นใจในตัวเองสูง มั่นใจในความแข็งแกร่งของตัวเองมาก และมีเป้าหมายที่จะเป็นเทรนเนอร์ที่ดีที่สุด',
		desc = '“火箭队老大？早就被我打败了！”\n“自从收服了固拉多，你知道这意味着什么吗？”\n“住口，你才不会飞！”\n“好了！让我来告诉你！本大爷！世界最强！比任何人都强！”',
		desc_tw = '“火箭隊老大？早就被我打敗了！”\n“自從收服了固拉多，你知道這意味著什麼嗎？”\n“住口，你才不會飛！”\n“好了！讓我來告訴你！本大爺！世界最強！比任何人都強！”',
		desc_en = 'The boss of Team Rocket? I\'ve defeated him long ago!"\n"Since captured Groudon, do you know what this means?"\n"Stop, you don\'t know how to fly!"\n"Okay! Let me tell you! I am the best in the world! Better than anyone!',
		desc_vn = 'Trùm của Đội Hỏa Tiễn? Tôi đã đánh bại hắn từ lâu rồi!\n"Từ khi bắt được Groudon, bạn có biết điều này có ý nghĩa gì không?"\n"Dừng lại, bạn không biết bay!"\n"Được rồi! Để tôi nói cho bạn biết! Tôi là người giỏi nhất thế giới! Giỏi hơn bất kỳ ai!"',
		desc_kr = '로켓단 대장? 벌써 나한테 졌구나!"\n"그란돈을 포획한 후부터 이게 무슨 의미인지 알아?"\n"입 닥쳐, 너야말로 날 수 없다!"\n"됐다! 내가 알려줄게! 나는! 세계 최강이다! 누구보다 강해!',
		desc_pt = 'O chefe da Equipe Rocket? Eu o derrotei há muito tempo!"\n"Desde que capturei Groudon, você sabe o que isso significa?"\n"Pare, você não sabe voar!"\n"Okay! Deixe-me dizer! Eu sou o melhor do mundo! Melhor do que qualquer um!',
		desc_th = '“หัวหน้าทีมร็อคเก็ตเหรอ ฉันเอาชนะมันมาตั้งนานแล้ว!”\n“ตั้งแต่จับกราวดอนมาได้ คุณรู้ไหมว่านี่หมายถึงอะไร?”\n“หยุดนะ แกบินไม่เป็น!”\n“โอเค บอกเลย! ฉันเก่งที่สุดในโลก! ดีกว่าใครๆ!”'
	},
	[5] = {
		id = 5,
		figure = 205,
		expertise = '"千里眼修验者"松叶热衷于传说的精灵，在缘朱市修行是想要一睹彩虹宝可梦凤王的风姿。通过修行他拥有了千里眼，能够看到其他人看不到的东西。',
		expertise_tw = '"千里眼修驗者"松葉熱衷於傳說的精靈，在緣朱市修行是想要一睹彩虹寶可夢鳳王的風姿。通過修行他擁有了千里眼，能夠看到其他人看不到的東西。',
		expertise_en = '"The Mystic Seer of the Future" Morty is keen on Legendary Pokémons, he practice in Ecruteak Gym is for a glimpse of Rainbow Pokémon Ho-oh. Through practice, he has clairvoyance and can see things that other people can\'t see.',
		expertise_vn = 'Nhà Tiên Tri Huyền Bí của Tương Lai Morty rất say mê Pokémon huyền thoại, anh ấy luyện tập tại Hội quán Ecruteak để được nhìn thấy Pokémon Cầu vồng Ho-oh. Thông qua luyện tập, anh có khả năng nhìn thấu và có thể thấy những điều mà người khác không thể thấy.',
		expertise_kr = '별명 \'천리안 수행자\'를 가진 유빈이 전설의 포켓몬을 열광하고 인주시티에서 수행하는 것은 무지개 포켓몬 칠색조의 자태를 보려기 때문이다. 수행을 통해 천리안을 갖게 되었고 남들이 볼 수 없는 것을 볼 수 있다.',
		expertise_pt = '"O Vidente Místico do Futuro" Morty é apaixonado por Pokémon Lendários, ele pratica no Ginásio Ecruteak para ter um vislumbre do Pokémon Arco-Íris Ho-oh. Através da prática, ele tem clarividência e pode ver coisas que outras pessoas não conseguem ver.',
		expertise_th = '"ผู้มองเห็นอนาคตอันลึกลับ" มอร์ตี้สนใจโปเกมอนในตำนาน เขาฝึกฝนที่ Ecruteak Gym เพื่อมองเห็นโปเกมอนสายรุ้ง Ho-oh ด้วยการฝึกฝน เขาจึงมีญาณพิเศษและสามารถมองเห็นสิ่งที่คนอื่นมองไม่เห็น',
		desc = '“即使没办法到达自己所相信的未来……”\n“我的未来也不会跟着消失。”\n“在看见新的未来之前，我会继续修行的。”\n“话说……似乎有人觉得缘朱道馆有些可怕，要不要在入口装饰一些花呢？”',
		desc_tw = '“即使沒辦法到達自己所相信的未來……”\n“我的未來也不會跟著消失。”\n“在看見新的未來之前，我會繼續修行的。”\n“話說……似乎有人覺得緣朱道館有些可怕，要不要在入口裝飾一些花呢？”',
		desc_en = 'Even if there is no way to reach the future I believe in..."\n"My future will not disappear."\n"Before I see a new future, I will continue to practice."\n"It seems that some people think Ecruteak Gym is a bit scary. Maybe decorate with some flowers at the entrance?',
		desc_vn = 'Ngay cả khi không có cách nào để đến được tương lai mà tôi tin tưởng...\n"Tương lai của tôi sẽ không biến mất."\n"Trước khi tôi nhìn thấy một tương lai mới, tôi sẽ tiếp tục luyện tập."\n"Dường như một số người nghĩ Hội Quán Ecruteak hơi đáng sợ. Có lẽ nên trang trí một ít hoa ở lối vào?"',
		desc_kr = '내가 믿는 미래에 이르지 못하더라도…"\n"내 미래는 사라지지 않는다."\n"새로운 미래를 볼 때까지 계속 수행하겠다."\n"그나저나… 인주 체육관이 무섭다고 생각하는 사람들이 있는 것 같은데 입구에서 꽃장식이라도 할까?',
		desc_pt = 'Mesmo que não haja nenhuma maneira de alcançar o futuro em que acredito..."\n"Meu futuro não desaparecerá."\n"Antes de ver um novo futuro, continuarei praticando."\n"Parece que algumas pessoas acham que o Ecruteak Gym é um pouco assustador. Talvez decorar com algumas flores na entrada?',
		desc_th = '“ถึงจะไม่มีทางไปถึงอนาคตได้ ฉันเชื่อใน...”\n“อนาคตของฉันจะไม่หายไป”\n“ก่อนที่ฉันจะมองเห็นอนาคตใหม่ ฉันจะฝึกฝนต่อไป”\n“ดูเหมือนว่าบางคนจะคิดว่า Ecruteak Gym น่ากลัวนิดหน่อย ลองประดับตกแต่งทางเข้าด้วยดอกไม้ดูไหม?”'
	},
	[6] = {
		id = 6,
		figure = 206,
		expertise = '在红莲研究所工作的高智商老人，性格开朗，爱开玩笑和猜谜，曾经在登山时遇难，被飞来照亮了昏暗山路的火焰鸟所救，这便成了他作为火属性训练家的契机。',
		expertise_tw = '在紅蓮研究所工作的高智商老人，性格開朗，愛開玩笑和猜謎，曾經在登山時遇難，被飛來照亮了昏暗山路的火焰鳥所救，這便成了他作為火屬性訓練家的契機。',
		expertise_en = 'An old man with a high IQ who works in the Cinnabar Lab, has an outgoing personality and loves to joke and puzzle. Once in danger while climbing, he was rescued by Moltres flying to illuminate the dim mountain road. This became his opportunity as a Fire-Type trainer.',
		expertise_vn = 'Một ông lão có IQ cao làm việc tại Phòng thí nghiệm Cinnabar, có tính cách hướng ngoại và thích đùa và đố vui. Có lần gặp nguy hiểm khi leo núi, ông đã được Moltres bay đến chiếu sáng con đường núi mờ tối cứu thoát. Đây đã trở thành cơ hội để ông trở thành một huấn luyện viên hệ Lửa.',
		expertise_kr = '홍련 연구소에서 일하는 지능이 높은 노인이 농담과 퀴즈를 즐기는 편이며, 산행 중 조난을 당해 어두운 산길을 밝혀 날아온 파이어에게 구조된 것은 불꽃 타입 훈련가로서의 계기가 되었다.',
		expertise_pt = 'Um velho com alto QI que trabalha no Laboratório Cinnabar, tem uma personalidade extrovertida e adora brincar e fazer quebra-cabeças. Uma vez em perigo enquanto escalava, ele foi resgatado por Moltres voando para iluminar a estrada escura da montanha. Esta se tornou sua oportunidade como um treinador do Tipo Fogo.',
		expertise_th = 'ชายชราผู้มี IQ สูงซึ่งทำงานในห้องแล็บซินนาบาร์ มีบุคลิกที่เปิดเผยและชอบพูดตลกและไขปริศนา เมื่อตกอยู่ในอันตรายขณะปีนเขา เขาได้รับการช่วยเหลือโดย Moltres โดยบินไปส่องแสงสว่างบนถนนภูเขาที่มืดสลัว นี่จึงกลายเป็นโอกาสของเขาในการเป็นผู้ฝึกสอนประเภทไฟ',
		desc = '“嘿~~！年轻人，请听题：烈焰猴喜欢捉鱼还是捕鸟？”\n“答案是捕鸟！因为他就叫「猎燕」猴啊！啊哈哈哈！”\n“嗯？你说我的头顶很耀眼？没礼貌！我这是聪明绝顶！”\n“龟仙人？那又是什么宝可梦？”',
		desc_tw = '“嘿~~！年輕人，請聽題：烈焰猴喜歡捉魚還是捕鳥？”\n“答案是捕鳥！因為他就叫「獵燕」猴啊！啊哈哈哈！”\n“嗯？你說我的頭頂很耀眼？沒禮貌！我這是聰明絕頂！”\n“龜仙人？那又是什麼寶可夢？”',
		desc_en = 'Hey! Young man, listen: What does Ash say when he wants to date someone?"\n"The answer is: I choose you.Hahahaha!"\n"Huh? You said my head is dazzling? That\'s rude! It\'s a symbol of being smart!"\n"MasterRoshi? What Pokémon is that?',
		desc_vn = 'Này! Chàng trai trẻ, nghe đây: Ash nói gì khi muốn hẹn hò với ai đó?\n"Câu trả lời là: Tôi chọn bạn.Hahahaha!"\n"Hả? Bạn nói đầu tôi chói lóa à? Thật là thô lỗ! Đó là biểu tượng của sự thông minh!"\n"Sư phụ Roshi? Đó là Pokémon gì vậy?"',
		desc_kr = '자~~! 청년, 문제 들어봐요: 초염몽은 물고기잡이를 좋아합니까? 아니면 새잡이를 좋아합니까?"\n"정답은 새잡이다! 아하하하!"\n"응? 내 정수리가 눈부시다고? 버릇없네! 이건 똑똑하는거야!"\n"거북 선인? 그게 또 무슨 포켓몬이야?',
		desc_pt = 'Ei! Rapaz, escuta: O que Ash diz quando quer namorar alguém?"\n"A resposta é: Eu escolho você. Hahahaha!"\n"Huh? Você disse que minha cabeça é deslumbrante? Isso é rude! É um símbolo de ser inteligente!"\n"Mestre Roshi? Que Pokémon é esse?',
		desc_th = '“เฮ้! หนุ่มน้อย ฟังนะ แอชจะพูดว่าอะไรเวลาเขาอยากออกเดทกับใครสักคน”\n“คำตอบคือ: ฉันเลือกนาย ฮ่าๆๆๆ!”\n“ห๊ะ? นายบอกว่าหัวของฉันแวววาวเหรอ? หยาบคายจัง! มันเป็นสัญลักษณ์ของความฉลาด!”\n“มาสเตอร์โรชิ? โปเกม่อนตัวไหนน่ะ?”'
	},
	[7] = {
		id = 7,
		figure = 207,
		expertise = '双龙市的市长，胡子形似龙的下颚，每天坚持与宝可梦摔跤来锻炼身体。曾参加过各种精灵训练师比赛，登入名人堂之后，便开始了自己的技艺传授之路。',
		expertise_tw = '雙龍市的市長，鬍子形似龍的下顎，每天堅持與寶可夢摔跤來鍛煉身體。曾參加過各種精靈訓練師比賽，登入名人堂之後，便開始了自己的技藝傳授之路。',
		expertise_en = 'Mayor of Opelucid City, with a beard like toothy lower jaw of a reptile, wrestling with Pokémon every day to exercise.Having participated in various Pokémon trainer competitions, and after enter the Hall of Fame, he began his own way of teaching skills.',
		expertise_vn = 'Thị trưởng thành phố Opelucid, với bộ râu giống như hàm dưới có răng của loài bò sát, ông đấu vật với Pokémon mỗi ngày để rèn luyện. Sau khi tham gia nhiều cuộc thi huấn luyện viên Pokémon và vào Đại Sảnh Danh Vọng, ông đã bắt đầu con đường dạy kỹ năng của riêng mình.',
		expertise_kr = '쌍용시티의 시장, 수염이 용의 아래턱과 닮으며, 매일 포켓몬과 씨름하여 몸을 단련하고 각종 포켓몬 훈련사 대회에 참가한 적이 있었다. 명예의 전당에 들어간 뒤 자기의 스킬을 전수하기 시작했다.',
		expertise_pt = 'Prefeito de Opelucid City, com uma barba parecida com a mandíbula dentada de um réptil, lutava com Pokémon todos os dias para se exercitar. Tendo participado de várias competições de treinadores Pokémon e depois de entrar no Hall da Fama, ele começou sua própria maneira de ensinar habilidades.',
		expertise_th = 'นายกเทศมนตรีเมืองโอเปลูซิด ผู้มีเครายาวเหมือนขากรรไกรล่างที่มีฟันเหมือนสัตว์เลื้อยคลาน กำลังต่อสู้กับโปเกมอนทุกวันเพื่อออกกำลังกาย หลังจากได้เข้าร่วมการแข่งขันเทรนเนอร์โปเกมอนหลายรายการ และเข้าสู่หอเกียรติยศแล้ว เขาก็เริ่มสอนทักษะในแบบฉบับของตัวเอง',
		desc = '“越是老！越是渴求胜利！这才是生命的能量！超越昨天的力量！”\n“我寻求着能让我看到光明未来的年轻训练家。”\n“感谢与你相遇，和你战斗的命运。”\n“你不仅要创造自己的未来，还要为他人带去光明的未来。”\n',
		desc_tw = '“越是老！越是渴求勝利！這才是生命的能量！超越昨天的力量！”\n“我尋求著能讓我看到光明未來的年輕訓練家。”\n“感謝與你相遇，和你戰鬥的命運。”\n“你不僅要創造自己的未來，還要為他人帶去光明的未來。”\n',
		desc_en = '"The older you are! The more you are thirsty for victory! This is the energy of life! Power beyond yesterday!"\n"I am looking for young trainers who can see a bright future for me."\n"Thank you for meeting you and fighting with you."\n"You must not only create your own future, but also bring a bright future for others."\n',
		desc_vn = 'Càng lớn tuổi! Càng khao khát chiến thắng! Đây là năng lượng của cuộc sống! Sức mạnh vượt qua ngày hôm qua!\n"Tôi đang tìm kiếm những huấn luyện viên trẻ có thể nhìn thấy một tương lai tươi sáng cho tôi."\n"Cảm ơn vì đã gặp bạn và chiến đấu cùng bạn."\n"Bạn không chỉ phải tạo ra tương lai của riêng mình, mà còn phải mang lại một tương lai tươi sáng cho người khác."',
		desc_kr = '"늙을수록! 승리에 갈구해라! 이것이야말로 생명의 에너지다! 어제의 힘을 넘게!"\n"나는 밝은 미래를 보여줄 수 있는 젊은 훈련가를 찾고 있다."\n"당신과 만나 싸워준 운명에 감사한다."\n"당신은 자신의 미래를 창조할 뿐만 아니라 다른 사람을 위해 밝은 미래고 가져와야 한다."\n',
		desc_pt = '"Quanto mais velho você é! Mais sedento você está pela vitória! Esta é a energia da vida! Poder além do ontem!"\n"Estou procurando por jovens treinadores que possam ver um futuro brilhante para mim."\n"Obrigado por conhecê-lo e lutar com você."\n"Você não deve apenas criar seu próprio futuro, mas também trazer um futuro brilhante para os outros."\n',
		desc_th = '“ยิ่งคุณอายุมากขึ้น! คุณยิ่งกระหายชัยชนะมากขึ้น! นี่คือพลังแห่งชีวิต! พลังเหนือเมื่อวาน!”\n“ฉันกำลังมองหาเทรนเนอร์รุ่นเยาว์ที่มองเห็นอนาคตที่สดใสสำหรับฉัน”\n“ขอบคุณที่ได้พบคุณและต่อสู้ไปกับคุณ”\n“คุณไม่เพียงแต่ต้องสร้างอนาคตของคุณเองเท่านั้น แต่ยังต้องนำอนาคตที่สดใสมาสู่ผู้อื่นด้วย”\n'
	},
	[8] = {
		id = 8,
		figure = 208,
		expertise = '"冰晶少女"小菘对流行、恋爱和精灵很有兴趣，为了让自己变得时尚，在寒冷的切锋市也穿着单衣和短裙，比起冷酷给人的距离感，小菘既温暖又友善。',
		expertise_tw = '"冰晶少女"小菘對流行、戀愛和精靈很有興趣，為了讓自己變得時尚，在寒冷的切鋒市也穿著單衣和短裙，比起冷酷給人的距離感，小菘既溫暖又友善。',
		expertise_en = '"The Diamond Dust Girl" Candice is interested in pop, love and Pokémon, in order to become fashionable, she also wears shirt and short skirts in the cold Snowpoint City. Instead of cold and emotionless, Candice is warm and friendly.',
		expertise_vn = 'Cô Gái Bụi Kim Cương Candice quan tâm đến nhạc pop, tình yêu và Pokémon, để trở nên thời trang, cô ấy cũng mặc áo sơ mi và váy ngắn ở thành phố Snowpoint lạnh giá. Thay vì lạnh lùng và vô cảm, Candice lại ấm áp và thân thiện.',
		expertise_kr = '유행, 연애, 포켓몬에 관심이 많은 \'얼음소녀\' 무청은 자신을 스타일리시하게 만들기 위해 추운 선단시티에서도 홑옷과 짧은 치마를 입는다. 차가운 거리감보다는 그녀가 따뜻하고 친절하다.',
		expertise_pt = '"The Diamond Dust Girl" Candice se interessa por pop, amor e Pokémon, para ficar na moda, ela também usa camisa e saias curtas na fria Snowpoint City. Em vez de fria e sem emoção, Candice é calorosa e amigável.',
		expertise_th = 'แคนดิซ "สาวไดมอนด์ดัสต์" สนใจเรื่องป็อป ความรัก และโปเกมอน เพื่อให้ดูทันสมัย เธอยังใส่เสื้อและกระโปรงสั้นในเมืองสโนว์พอยต์อันหนาวเหน็บอีกด้วย แทนที่จะดูเย็นชาและไร้ความรู้สึก แคนดิซกลับดูอบอุ่นและเป็นมิตร',
		desc = '“冷酷留给招式就够了！斗志要火热燃烧才够酷吧？”\n“用炽热的心融化寒冷的冰！这就是我小菘的宝可梦对战！”\n“不论到哪里，我小菘和宝可梦的气势都不会输给別人！”',
		desc_tw = '“冷酷留給招式就夠了！鬥志要火熱燃燒才夠酷吧？”\n“用熾熱的心融化寒冷的冰！這就是我小菘的寶可夢對戰！”\n“不論到哪裡，我小菘和寶可夢的氣勢都不會輸給別人！”',
		desc_en = 'The coldness is enough for the moves! The fighting spirit is cool enough to burn, right?"\n"Melt the cold ice with a fiery heart! This is my Pokémon battle!"\n"Wherever you go,me Candice and my Pokémon won\'t lose!',
		desc_vn = 'Sự lạnh lẽo là đủ cho các chiêu thức! Tinh thần chiến đấu đủ ngầu để bùng cháy, đúng không?\n"Làm tan chảy băng giá lạnh lẽo bằng một trái tim rực lửa! Đây là trận chiến Pokémon của tôi!"\n"Dù đi đâu, tôi Candice và Pokémon của tôi sẽ không thua!"',
